sql:
SELECT u.user_name, m.model_name
FROM users u
JOIN models m ON u.user_id = m.created_by;

SELECT DISTINCT users.user_name
FROM models
INNER JOIN users ON models.created_by = users.user_id;

SELECT relationship_type 
FROM model_element_relationships 
WHERE relationship_id = 0;

SELECT models.model_name, model_versions.version_number, models.created_at
FROM models
INNER JOIN model_versions ON models.model_id = model_versions.model_id;

SELECT AVG(num_versions) AS avg_versions
FROM (
  SELECT created_by, COUNT(*) AS num_versions
  FROM model_versions
  GROUP BY created_by
) AS temp;

SELECT DISTINCT model_id
FROM model_versions
WHERE version_status = 'draft' AND last_modified_at > '2023-01-01 00:00:00';

SELECT type_name, type_id 
FROM model_element_types 
WHERE type_name = 'BPMNElement';
